INSERT INTO public.lessons (id,course_id,title,content_type,url,file_path,article_content,estimated_minutes,sort_order) VALUES
  ('a1c10900-0000-4000-8000-000000000000','a1c00000-0000-4000-8000-000000000000','確認テスト ─ 予算とは何か','quiz',NULL,NULL,NULL,3,2),
  ('a1c20900-0000-4000-8000-000000000000','a1c00000-0000-4000-8000-000000000000','確認テスト ─ KPIの読み方と作り方','quiz',NULL,NULL,NULL,3,4),
  ('a1c30900-0000-4000-8000-000000000000','a1c00000-0000-4000-8000-000000000000','確認テスト ─ 簡単な事業計画（ワンページプラン）','quiz',NULL,NULL,NULL,3,6)
INSERT INTO public.quiz_questions (lesson_id,question,option_a,option_b,option_c,option_d,correct_option,sort_order) VALUES
('a1c10900-0000-4000-8000-000000000000','本文が示す「予算」の定義はどれか。','上から押しつけられ、達成を迫られるノルマ','やりたいことを、数字で約束したもの','過去の成果を裁くための成績表','経理担当者だけが扱う勘定科目の集計','B',0),
('a1c10900-0000-4000-8000-000000000000','予実差を見る目的として、本文が正しいとするのはどれか。','誰のせいで足りないのか、犯人を特定するため','すべての勘定科目を漏れなく理解するため','約束と現実のズレを淡々と把握し、次の一手の出発点にするため','上司に謝罪すべきかどうかを決めるため','C',1),
('a1c10900-0000-4000-8000-000000000000','費用が予算を超えそうだと見えたとき、本文がやるべきだと説く行動はどれか。','期末まで一人で抱え込み、隠しきれなくなってから報告する','完璧な原因分析を終えてから報告する','現場が正しいと信じ、予算は無視して進める','早めに、数字と原因の見立てを添えて上司に相談する','D',2),
('a1c20900-0000-4000-8000-000000000000','本文が示すKPIの本質はどれか。','上に提出するための報告用の数字','最終的に到達したいゴールそのものの数字','ゴールに近づいているかを測る、途中の目印','メンバーがサボっていないかを監視する数字','C',0),
('a1c20900-0000-4000-8000-000000000000','本文でいう「先行指標」にあたるのはどれか。','売上や契約数など、もう起きてしまった結果の数字','商談の数や声かけの回数など、結果が出る前の行動の数字','月末にしか締まらない集計の数字','相手の判断で決まる成約の数字','B',1),
('a1c20900-0000-4000-8000-000000000000','数字が落ちたとき、本文が良いとするリーダーの口の開き方はどれか。','「君の数字、また届いてないよね。」','「今週、目標に届いてないけど、どうなってるの。」','「今週、声かけが先週より5件少ない。何か、動きにくかったことがあった?」','「すみません、達成できそうになくて。」','C',2),
('a1c30900-0000-4000-8000-000000000000','本文が示す事業計画の本質はどれか。','市場規模や五年分の数字を並べた、分厚い立派な書類','誰に、何を、どう届け、どうなりたいかを、一枚で言えること','競合の一覧を漏れなく網羅した調査資料','上に提出して承認をもらうための成果物','B',0),
('a1c30900-0000-4000-8000-000000000000','ワンページに書く「③何を」で、本文が正しいとする書き方はどれか。','届ける商品の機能やスペックを詳しく説明する','儲かる見込みの金額を書く','その一人が使った結果、どんな状態になれるか(相手の変化)を書く','ターゲットを幅広く、多くの人にと広げて書く','C',1),
('a1c30900-0000-4000-8000-000000000000','「⑥最初の一歩」について、本文が説く鉄則はどれか。','事業を立ち上げるような、大きな一歩を掲げる','明日できるくらい小さい一歩にする','完璧な設計図が固まるまで踏み出さない','数字の目標が達成できてから決める','B',2);
